class SketchSnapshotIdentityTest {

	private static final String IDENTITY_CLASS = "org.eclipse.rdf4j.sail.lmdb.sketch.SketchSnapshotIdentity";

	@Test
	void fixedWidthRoundTripPreservesStoreAndMutationIdentity() throws Exception {
		Class<?> identityType = Class.forName(IDENTITY_CLASS);
		Constructor<?> constructor = identityType.getConstructor(long.class, long.class, long.class);
		Object identity = constructor.newInstance(0x0123_4567_89AB_CDEFL, 0xFEDC_BA98_7654_3210L, 41L);

		ByteArrayOutputStream bytes = new ByteArrayOutputStream();
		try (DataOutputStream out = new DataOutputStream(bytes)) {
			identityType.getMethod("writeTo", DataOutput.class).invoke(identity, out);
		}

		assertEquals(3 * Long.BYTES, bytes.size(), "Identity encoding must stay fixed-width");
		Object decoded;
		try (DataInputStream in = new DataInputStream(new ByteArrayInputStream(bytes.toByteArray()))) {
			decoded = identityType.getMethod("readFrom", DataInput.class).invoke(null, in);
		}
		assertEquals(identity, decoded);
		assertEquals(41L, identityType.getMethod("mutationVersion").invoke(decoded));
	}

	@Test
	void storeMatchingIgnoresVersionButEqualityDoesNot() throws Exception {
		Class<?> identityType = Class.forName(IDENTITY_CLASS);
		Constructor<?> constructor = identityType.getConstructor(long.class, long.class, long.class);
		Object first = constructor.newInstance(11L, 12L, 1L);
		Object later = constructor.newInstance(11L, 12L, 2L);
		Object otherStore = constructor.newInstance(11L, 13L, 1L);
		Method sameStore = identityType.getMethod("sameStore", identityType);

		assertTrue((boolean) sameStore.invoke(first, later));
		assertFalse((boolean) sameStore.invoke(first, otherStore));
		assertFalse(first.equals(later));
	}

	@Test
	void negativeMutationVersionIsRejected() throws Exception {
		Class<?> identityType = Class.forName(IDENTITY_CLASS);
		Constructor<?> constructor = identityType.getConstructor(long.class, long.class, long.class);

		InvocationTargetException failure = assertThrows(InvocationTargetException.class,
				() -> constructor.newInstance(1L, 2L, -1L));

		assertInstanceOf(IllegalArgumentException.class, failure.getCause());
	}

	@Test
	void metadataCarriesOptionalColdSynopsisReference() throws IOException {
		SketchEstimatorMetadata metadata = new SketchEstimatorMetadata(4, 4, 4, 4, true,
				SketchBasedJoinEstimator.SketchStrategy.OMNI, 64, "urn:default", (byte) 0, 12L, 13L, 14L, 1L,
				2L, null, null, new SketchSnapshotIdentity(3L, 4L, 5L), 6_144,
				"join-estimator.rjes.cold");
		ByteArrayOutputStream bytes = new ByteArrayOutputStream();
		try (DataOutputStream out = new DataOutputStream(bytes)) {
			metadata.writeTo(out);
		}

		SketchEstimatorMetadata restored;
		try (DataInputStream in = new DataInputStream(new ByteArrayInputStream(bytes.toByteArray()))) {
			restored = SketchEstimatorMetadata.readFrom(in);
		}
		assertEquals(6_144, restored.coldSynopsisCapacity);
		assertEquals("join-estimator.rjes.cold", restored.coldSynopsisReference());
		assertEquals(metadata.snapshotIdentity(), restored.snapshotIdentity());
	}

	@Test
	void mutationCycleRestoresCommittedVersionBeforeNewMutations() throws Exception {
		PersistenceMutationCycle cycle = new PersistenceMutationCycle();
		Method currentVersion = PersistenceMutationCycle.class.getDeclaredMethod("currentVersion");
		Method persistedVersion = PersistenceMutationCycle.class.getDeclaredMethod("persistedVersion");
		Method restore = PersistenceMutationCycle.class.getDeclaredMethod("restorePersistedVersion", long.class);
		currentVersion.setAccessible(true);
		persistedVersion.setAccessible(true);
		restore.setAccessible(true);

		restore.invoke(cycle, 7L);

		assertEquals(7L, currentVersion.invoke(cycle));
		assertEquals(7L, persistedVersion.invoke(cycle));
		assertFalse(cycle.hasUnpersistedMutations());
		cycle.mutationEnqueued();
		assertEquals(8L, currentVersion.invoke(cycle));
		assertEquals(7L, persistedVersion.invoke(cycle));
		assertTrue(cycle.hasUnpersistedMutations());
	}

	@Test
	void persistedIdentitySurvivesRestartAndAdvancesAfterMutation(@TempDir Path tempDir) throws Exception {
		var valueFactory = SimpleValueFactory.getInstance();
		Path snapshot = tempDir.resolve("join-estimator.rjes");
		SketchBasedJoinEstimator.Config config = SketchBasedJoinEstimator.Config.defaults()
				.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.COUNT_MIN_DUAL)
				.withNominalEntries(64);
		Object firstIdentity;
		SketchBasedJoinEstimator writer = new SketchBasedJoinEstimator(new StubSketchStatementSource(), config);
		try {
			writer.configurePersistence(snapshot, false);
			writer.addStatement(valueFactory.createStatement(valueFactory.createIRI("urn:identity:s1"),
					valueFactory.createIRI("urn:identity:p"), valueFactory.createIRI("urn:identity:o1")));
			assertTrue(writer.persistIfDirty());
			firstIdentity = snapshotIdentity(writer);
		} finally {
			writer.close();
		}

		SketchBasedJoinEstimator reader = new SketchBasedJoinEstimator(new StubSketchStatementSource(), config);
		try {
			reader.configurePersistence(snapshot, false);
			Object restoredIdentity = snapshotIdentity(reader);
			assertEquals(firstIdentity, restoredIdentity);

			reader.addStatement(valueFactory.createStatement(valueFactory.createIRI("urn:identity:s2"),
					valueFactory.createIRI("urn:identity:p"), valueFactory.createIRI("urn:identity:o2")));
			assertTrue(reader.persistIfDirty());
			Object laterIdentity = snapshotIdentity(reader);
			Class<?> identityType = Class.forName(IDENTITY_CLASS);
			assertTrue((boolean) identityType.getMethod("sameStore", identityType)
					.invoke(firstIdentity, laterIdentity));
			long firstVersion = (long) identityType.getMethod("mutationVersion").invoke(firstIdentity);
			long laterVersion = (long) identityType.getMethod("mutationVersion").invoke(laterIdentity);
			assertTrue(laterVersion > firstVersion);
		} finally {
			reader.close();
		}
	}

	private static Object snapshotIdentity(SketchBasedJoinEstimator estimator) throws Exception {
		return SketchBasedJoinEstimator.class.getMethod("snapshotIdentity").invoke(estimator);
	}
}
